package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// TempValeConfig holds paths to a temporary Vale configuration scoped to one invocation.
type TempValeConfig struct {
	dir     string
	iniPath string
}

// INIPath returns the path to the generated .vale.ini file.
func (t *TempValeConfig) INIPath() string {
	return t.iniPath
}

// StylesPath returns the absolute styles directory written into the generated .vale.ini.
func (t *TempValeConfig) StylesPath() string {
	return filepath.Join(t.dir, "styles")
}

// Cleanup removes all temporary files created for this config.
func (t *TempValeConfig) Cleanup() {
	os.RemoveAll(t.dir)
}

// NewTempValeConfig generates a temporary Vale configuration from DDx settings.
// StylesPath is pointed at the packaged DDx styles via a symlink so no copy is needed.
// Project vocabulary is rendered into Vale accept/reject files under Vocab/Project/.
// The caller must call Cleanup() when done.
func NewTempValeConfig(settings Settings) (*TempValeConfig, error) {
	assetRoot, err := defaultAssetRoot()
	if err != nil {
		return nil, fmt.Errorf("resolve asset root: %w", err)
	}
	packagedDDxStyles := filepath.Join(assetRoot, "styles", "DDx")

	dir, err := os.MkdirTemp("", "ddx-vale-")
	if err != nil {
		return nil, fmt.Errorf("create temp vale dir: %w", err)
	}

	stylesDir := filepath.Join(dir, "styles")
	if err := os.MkdirAll(stylesDir, 0o755); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("create styles dir: %w", err)
	}

	// Symlink the packaged DDx style directory so we avoid copying rule files.
	if err := os.Symlink(packagedDDxStyles, filepath.Join(stylesDir, "DDx")); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("symlink DDx styles: %w", err)
	}

	vocabName := ""
	if len(settings.Vocabulary.Accept) > 0 || len(settings.Vocabulary.Reject) > 0 {
		vocabName = "Project"
		vocabDir := filepath.Join(stylesDir, "Vocab", vocabName)
		if err := os.MkdirAll(vocabDir, 0o755); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("create vocab dir: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "accept.txt"), settings.Vocabulary.Accept); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write accept vocabulary: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "reject.txt"), settings.Vocabulary.Reject); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write reject vocabulary: %w", err)
		}
	}

	style := settings.Vale.Style
	if style == "" {
		style = "DDx"
	}

	iniPath := filepath.Join(dir, ".vale.ini")
	ini := buildValeINI(stylesDir, style, vocabName)
	if err := os.WriteFile(iniPath, []byte(ini), 0o644); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("write .vale.ini: %w", err)
	}

	return &TempValeConfig{dir: dir, iniPath: iniPath}, nil
}

func buildValeINI(stylesPath, style, vocabName string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "StylesPath = %s\n", stylesPath)
	fmt.Fprintf(&b, "MinAlertLevel = suggestion\n")
	if vocabName != "" {
		fmt.Fprintf(&b, "Vocab = %s\n", vocabName)
	}
	fmt.Fprintf(&b, "\n[*.md]\n")
	fmt.Fprintf(&b, "BasedOnStyles = %s\n", style)
	return b.String()
}

func writeTextLines(path string, lines []string) error {
	content := strings.Join(lines, "\n")
	if len(lines) > 0 {
		content += "\n"
	}
	return os.WriteFile(path, []byte(content), 0o644)
}

package docprose

import ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"

// Settings captures the prose-quality defaults packaged with DDx.
type Settings struct {
	Mode       Mode
	Severity   string
	Policy     string
	Runner     string
	Vale       ValeConfig
	StylePack  StylePack
	Includes   []string
	Excludes   []string
	Vocabulary Vocabulary
}

// DefaultSettings returns the packaged prose-quality defaults from the
// embedded check asset tree.
func DefaultSettings() (Settings, error) {
	cfg, err := loadDefaultConfig()
	if err != nil {
		return Settings{}, err
	}
	return Settings{
		Mode:     Mode(cfg.Mode),
		Severity: cfg.Severity,
		Policy:   cfg.Policy,
		Runner:   cfg.Runner,
		Vale: ValeConfig{
			Version:    cfg.Vale.Version,
			StylesPath: cfg.Vale.StylesPath,
			Style:      cfg.Vale.Style,
		},
		StylePack: StylePack{
			Name:    cfg.StylePack.Name,
			Version: cfg.StylePack.Version,
			Path:    cfg.StylePack.Path,
			Rules:   append([]StyleRule(nil), cfg.StylePack.Rules...),
		},
		Includes: append([]string(nil), cfg.Includes...),
		Excludes: append([]string(nil), cfg.Excludes...),
		Vocabulary: Vocabulary{
			DefaultPath: cfg.Vocabulary.DefaultPath,
			ValeStyle:   cfg.Vocabulary.ValeStyle,
			Accept:      append([]string(nil), cfg.Vocabulary.Accept...),
			Reject:      append([]string(nil), cfg.Vocabulary.Reject...),
		},
	}, nil
}

// ResolveSettings returns the effective prose-quality settings after layering
// any project configuration onto the packaged defaults.
func ResolveSettings(cfg *ddxconfig.Config) (Settings, error) {
	settings, err := DefaultSettings()
	if err != nil {
		return Settings{}, err
	}
	if cfg == nil || cfg.Prose == nil {
		return settings, nil
	}

	if cfg.Prose.Mode != "" {
		settings.Mode = Mode(cfg.Prose.Mode)
	}
	if cfg.Prose.Severity != "" {
		settings.Severity = cfg.Prose.Severity
	}
	if cfg.Prose.Policy != "" {
		settings.Policy = cfg.Prose.Policy
	}
	if cfg.Prose.Runner != "" {
		settings.Runner = cfg.Prose.Runner
	}
	if len(cfg.Prose.Includes) > 0 {
		settings.Includes = append([]string(nil), cfg.Prose.Includes...)
	}
	if len(cfg.Prose.Excludes) > 0 {
		settings.Excludes = append([]string(nil), cfg.Prose.Excludes...)
	}
	if cfg.Prose.Vocabulary != nil {
		if len(cfg.Prose.Vocabulary.Accept) > 0 {
			settings.Vocabulary.Accept = append([]string(nil), cfg.Prose.Vocabulary.Accept...)
		}
		if len(cfg.Prose.Vocabulary.Reject) > 0 {
			settings.Vocabulary.Reject = append([]string(nil), cfg.Prose.Vocabulary.Reject...)
		}
	}

	return settings, nil
}

package docprose

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestDocProseValeConfig_NoProjectValeINI(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	data, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatalf("read generated .vale.ini: %v", err)
	}
	if len(data) == 0 {
		t.Fatal("generated .vale.ini is empty")
	}
	content := string(data)
	if !strings.Contains(content, "StylesPath") {
		t.Error("generated .vale.ini is missing StylesPath")
	}
	if !strings.Contains(content, "[*.md]") {
		t.Error("generated .vale.ini is missing [*.md] section")
	}
	if !strings.Contains(content, "BasedOnStyles") {
		t.Error("generated .vale.ini is missing BasedOnStyles")
	}
}

func TestDocProseValeConfig_StylesPathUsesPackagedRules(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	// DDx style directory must be accessible via the generated StylesPath.
	ddxStyleDir := filepath.Join(cfg.StylesPath(), "DDx")
	info, err := os.Stat(ddxStyleDir)
	if err != nil {
		t.Fatalf("DDx style dir not accessible at %s: %v", ddxStyleDir, err)
	}
	if !info.IsDir() {
		t.Fatalf("expected %s to be a directory", ddxStyleDir)
	}

	// The INI file must reference the generated StylesPath.
	data, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(string(data), cfg.StylesPath()) {
		t.Errorf("generated .vale.ini does not reference expected StylesPath %s\ncontent:\n%s", cfg.StylesPath(), string(data))
	}
}

func TestDocProseValeConfig_ProjectVocabularyRendered(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}
	settings.Vocabulary.Accept = []string{"DDx", "bead", "Quartz"}
	settings.Vocabulary.Reject = []string{"system"}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	// accept.txt must contain each accept term.
	acceptPath := filepath.Join(cfg.StylesPath(), "Vocab", "Project", "accept.txt")
	data, err := os.ReadFile(acceptPath)
	if err != nil {
		t.Fatalf("read accept.txt: %v", err)
	}
	acceptContent := string(data)
	for _, term := range []string{"DDx", "bead", "Quartz"} {
		if !strings.Contains(acceptContent, term) {
			t.Errorf("accept.txt missing term %q", term)
		}
	}

	// reject.txt must contain each reject term.
	rejectPath := filepath.Join(cfg.StylesPath(), "Vocab", "Project", "reject.txt")
	data, err = os.ReadFile(rejectPath)
	if err != nil {
		t.Fatalf("read reject.txt: %v", err)
	}
	if !strings.Contains(string(data), "system") {
		t.Error("reject.txt missing term 'system'")
	}

	// The INI must declare the Vocab directive.
	iniData, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(string(iniData), "Vocab") {
		t.Error("generated .vale.ini does not declare Vocab directive")
	}
}

func TestDocProseValeConfig_CleansTemporaryFiles(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}
	settings.Vocabulary.Accept = []string{"DDx"}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}

	iniPath := cfg.INIPath()
	tempDir := filepath.Dir(iniPath)

	if _, err := os.Stat(iniPath); err != nil {
		t.Fatalf("expected .vale.ini to exist before cleanup: %v", err)
	}

	cfg.Cleanup()

	if _, err := os.Stat(iniPath); !os.IsNotExist(err) {
		t.Errorf("expected .vale.ini to be removed after Cleanup, got: %v", err)
	}
	if _, err := os.Stat(tempDir); !os.IsNotExist(err) {
		t.Errorf("expected temp dir %s to be removed after Cleanup, got: %v", tempDir, err)
	}
}

package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"runtime"

	"gopkg.in/yaml.v3"
)

const assetRootDir = "library/checks/prose-quality"

type defaultConfig struct {
	Mode       string     `yaml:"mode"`
	Severity   string     `yaml:"severity"`
	Policy     string     `yaml:"policy"`
	Runner     string     `yaml:"runner"`
	Vale       ValeConfig `yaml:"vale"`
	StylePack  StylePack  `yaml:"rule_pack"`
	Includes   []string   `yaml:"includes"`
	Excludes   []string   `yaml:"excludes"`
	Vocabulary Vocabulary `yaml:"vocabulary"`
}

type ValeConfig struct {
	Version    string `yaml:"version"`
	StylesPath string `yaml:"styles_path"`
	Style      string `yaml:"style"`
}

type StylePack struct {
	Name    string      `yaml:"name"`
	Version string      `yaml:"version"`
	Path    string      `yaml:"path"`
	Rules   []StyleRule `yaml:"rules"`
}

type StyleRule struct {
	File   string `yaml:"file"`
	RuleID string `yaml:"rule_id"`
}

type rulePack struct {
	Mode  string     `yaml:"mode"`
	Rules []ruleSpec `yaml:"rules"`
}

type ruleSpec struct {
	ID            string   `yaml:"id"`
	Severity      string   `yaml:"severity"`
	Rationale     string   `yaml:"rationale"`
	SuggestedEdit string   `yaml:"suggested_edit"`
	ContainsAny   []string `yaml:"contains_any,omitempty"`
	Kind          string   `yaml:"kind,omitempty"`
}

type Vocabulary struct {
	DefaultPath string   `yaml:"default_path,omitempty"`
	ValeStyle   string   `yaml:"vale_style,omitempty"`
	Accept      []string `yaml:"accept"`
	Reject      []string `yaml:"reject"`
}

func defaultAssetRoot() (string, error) {
	_, file, _, ok := runtime.Caller(0)
	if !ok {
		return "", fmt.Errorf("locate docprose assets: runtime caller unavailable")
	}
	dir := filepath.Dir(file)
	root := filepath.Clean(filepath.Join(dir, "..", "..", ".."))
	return filepath.Join(root, assetRootDir), nil
}

func loadDefaultConfig() (defaultConfig, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return defaultConfig{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "check.yaml"))
	if err != nil {
		return defaultConfig{}, fmt.Errorf("read default config: %w", err)
	}
	var cfg defaultConfig
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return defaultConfig{}, fmt.Errorf("parse default config: %w", err)
	}
	return cfg, nil
}

func loadRulePack(mode string) ([]ruleSpec, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return nil, err
	}
	data, err := os.ReadFile(filepath.Join(root, "rules", mode+".yaml"))
	if err != nil {
		return nil, fmt.Errorf("read %s rules: %w", mode, err)
	}
	var pack rulePack
	if err := yaml.Unmarshal(data, &pack); err != nil {
		return nil, fmt.Errorf("parse %s rules: %w", mode, err)
	}
	if pack.Mode != mode {
		return nil, fmt.Errorf("rules file mode %q does not match requested mode %q", pack.Mode, mode)
	}
	return pack.Rules, nil
}

func loadDefaultVocabulary() (Vocabulary, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return Vocabulary{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "vocabulary", "default.yaml"))
	if err != nil {
		return Vocabulary{}, fmt.Errorf("read default vocabulary: %w", err)
	}
	var vocab Vocabulary
	if err := yaml.Unmarshal(data, &vocab); err != nil {
		return Vocabulary{}, fmt.Errorf("parse default vocabulary: %w", err)
	}
	return vocab, nil
}

package cmd

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docprose"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newDocProseCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "prose [paths...]",
		Short: "Check prose quality in Markdown documents",
		Long: `Check prose quality in changed Markdown files or explicit paths.

The default surface is advisory. Findings are deterministic and
machine-readable, with file, line, rule id, severity, rationale, and
suggested edit fields.`,
		Args: cobra.ArbitraryArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			return f.runDocProse(cmd, args)
		},
	}
	cmd.Flags().Bool("changed", false, "Check changed Markdown files in the current git repo")
	return cmd
}

func (f *CommandFactory) runDocProse(cmd *cobra.Command, args []string) error {
	changed, _ := cmd.Flags().GetBool("changed")

	cfg, err := config.LoadWithWorkingDir(f.docRoot())
	if err != nil {
		return err
	}

	settings, err := docprose.ResolveSettings(cfg)
	if err != nil {
		return err
	}

	if err := maybeReportMissingRunner(cmd, settings.Runner); err != nil {
		return err
	}

	rootDir := f.docRoot()
	var relPaths []string
	if changed {
		if len(args) > 0 {
			return fmt.Errorf("use either --changed or explicit paths, not both")
		}
		relPaths, err = changedMarkdownPaths(rootDir)
		if err != nil {
			return err
		}
	} else {
		if len(args) == 0 {
			return fmt.Errorf("provide one or more paths or pass --changed")
		}
		relPaths = append([]string(nil), args...)
	}

	checker, err := docprose.NewChecker(settings.Mode, settings.Vocabulary)
	if err != nil {
		return err
	}

	var findings []docprose.Finding
	for _, relPath := range relPaths {
		cleanRel, absPath, ok := normalizeDocPath(rootDir, relPath)
		if !ok {
			continue
		}
		if !strings.EqualFold(filepath.Ext(cleanRel), ".md") {
			continue
		}
		if !pathAllowed(cleanRel, settings.Includes, settings.Excludes) {
			continue
		}
		content, readErr := os.ReadFile(absPath)
		if readErr != nil {
			if os.IsNotExist(readErr) {
				continue
			}
			return fmt.Errorf("read %s: %w", relPath, readErr)
		}
		for _, finding := range checker.Findings(cleanRel, string(content)) {
			if settings.Severity != "" {
				finding.Severity = settings.Severity
			}
			findings = append(findings, finding)
		}
	}

	sort.Slice(findings, func(i, j int) bool {
		if findings[i].File != findings[j].File {
			return findings[i].File < findings[j].File
		}
		if findings[i].Line != findings[j].Line {
			return findings[i].Line < findings[j].Line
		}
		return findings[i].RuleID < findings[j].RuleID
	})

	out := cmd.OutOrStdout()
	if len(findings) == 0 {
		if changed {
			fmt.Fprintln(out, "No changed Markdown prose findings.")
		} else {
			fmt.Fprintln(out, "No prose findings.")
		}
		return nil
	}

	for _, finding := range findings {
		fmt.Fprintf(out, "%s:%d [%s] %s\n", finding.File, finding.Line, finding.Severity, finding.RuleID)
		fmt.Fprintf(out, "  rationale: %s\n", finding.Rationale)
		fmt.Fprintf(out, "  suggested edit: %s\n", finding.SuggestedEdit)
	}

	if isBlockingProsePolicy(settings.Policy, settings.Severity) {
		cmd.SilenceUsage = true
		cmd.SilenceErrors = true
		return NewExitError(ExitCodeGeneralError, "")
	}
	return nil
}

func maybeReportMissingRunner(cmd *cobra.Command, runner string) error {
	runner = strings.TrimSpace(strings.ToLower(runner))
	switch runner {
	case "", "embedded":
		return nil
	case "auto", "vale":
		if _, err := exec.LookPath("vale"); err != nil {
			fmt.Fprintf(cmd.ErrOrStderr(), "warning: optional prose runner %q is unavailable; using embedded checker\n", "vale")
		}
		return nil
	default:
		return fmt.Errorf("unsupported prose runner %q", runner)
	}
}

func isBlockingProsePolicy(policy, severity string) bool {
	return strings.EqualFold(policy, "blocking") || strings.EqualFold(severity, "blocking")
}

func changedMarkdownPaths(rootDir string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), rootDir, "status", "--porcelain=v1", "--untracked-files=all").Output()
	if err != nil {
		return nil, fmt.Errorf("git status failed: %w", err)
	}

	var paths []string
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		if line == "" || len(line) < 3 {
			continue
		}
		status := line[:2]
		pathText := strings.TrimSpace(line[3:])
		if pathText == "" {
			continue
		}
		if strings.Contains(pathText, " -> ") {
			parts := strings.Split(pathText, " -> ")
			pathText = parts[len(parts)-1]
		}
		if strings.ContainsRune(status, 'D') {
			continue
		}
		if !strings.EqualFold(filepath.Ext(pathText), ".md") {
			continue
		}
		paths = append(paths, filepath.ToSlash(pathText))
	}
	sort.Strings(paths)
	return paths, nil
}

func normalizeDocPath(rootDir, input string) (string, string, bool) {
	if strings.TrimSpace(input) == "" {
		return "", "", false
	}
	absPath := input
	if !filepath.IsAbs(input) {
		absPath = filepath.Join(rootDir, input)
	}
	absPath = filepath.Clean(absPath)
	relPath, err := filepath.Rel(rootDir, absPath)
	if err != nil {
		relPath = filepath.ToSlash(filepath.Clean(input))
	} else {
		relPath = filepath.ToSlash(relPath)
	}
	return relPath, absPath, true
}

func pathAllowed(relPath string, includes, excludes []string) bool {
	relPath = filepath.ToSlash(relPath)
	if len(includes) > 0 && !anyGlobMatch(includes, relPath) {
		return false
	}
	if len(excludes) > 0 && anyGlobMatch(excludes, relPath) {
		return false
	}
	return true
}

func anyGlobMatch(patterns []string, relPath string) bool {
	for _, pattern := range patterns {
		if matchPathGlob(pattern, relPath) {
			return true
		}
	}
	return false
}

func matchPathGlob(pattern, name string) bool {
	pattern = filepath.ToSlash(pattern)
	name = filepath.ToSlash(name)
	if matched, _ := filepath.Match(pattern, name); matched {
		return true
	}
	if matched, _ := filepath.Match(pattern, filepath.Base(name)); matched {
		return true
	}
	if !strings.Contains(pattern, "**") {
		return false
	}
	return matchDoubleStar(strings.Split(pattern, "/"), strings.Split(name, "/"))
}

